import { useState } from "react";
import { Card, AddCard, TodoCard } from "./Card";

const TodoBox = function ({ handleModal, todos, setTodos, filter, setFilterTodos, filterTodos }) {
    const filTodos = function () {
        setFilterTodos(todos.filter((todo) => todo.status === filter));
    };
    return (
        <>
            <div className="todo-box">
                <Card cl={"add-card"}>
                    <AddCard handleModal={handleModal} />
                </Card>
                {filterTodos.map((todo) => {
                    return (
                        <Card cl={"todo-card"} status={todo.status} key={todo.id}>
                            <TodoCard todo={todo} setTodos={setTodos} />
                        </Card>
                    );
                })}
            </div>
        </>
    );
};
export default TodoBox;
